// ============================================================
// Code Node 1: "Calculate - KPIs & Build Prompt"
// Reads merged rows from Google / Meta / Microsoft tabs
// Outputs: kpi object + groqPrompt string
// ============================================================

const num = v => parseFloat(String(v).replace(/[,%$\s]/g,'')) || 0;

function detectPlatform(r) {
  if (r['Platform']) return r['Platform'];
  if (r['Campaign name'] !== undefined) return 'Meta';
  if (r['Campaign status'] !== undefined) return 'Google';
  if (r['Status'] !== undefined && r['Impr.'] !== undefined) return 'Microsoft';
  return null;
}

function normalise(r) {
  const p = detectPlatform(r);
  if (p === 'Google') return {
    platform:'Google', campaign:String(r['Campaign']||''),
    status:String(r['Campaign status']||''), type:String(r['Campaign type']||''),
    impressions:num(String(r['Impr.']||'').replace(/,/g,'')),
    clicks:num(r['Clicks']), spend:num(r['Cost']),
    conversions:num(r['Conversions']), roas:num(r['Conv. value / cost']),
    cpm:0, purchases:num(r['Conversions']), budget:num(r['Budget']),
  };
  if (p === 'Microsoft') return {
    platform:'Microsoft', campaign:String(r['Campaign']||''),
    status:String(r['Status']||''), type:String(r['Campaign Type']||''),
    impressions:num(String(r['Impr.']||'').replace(/,/g,'')),
    clicks:num(r['Clicks']), spend:num(r['Spend']),
    conversions:num(r['Conv.']), roas:0,
    cpm:0, purchases:num(r['Conv.']), budget:num(r['Budget']),
  };
  if (p === 'Meta') return {
    platform:'Meta', campaign:String(r['Campaign name']||''),
    status:String(r['Campaign delivery']||''), type:'Social',
    impressions:num(r['Impressions']), clicks:0,
    spend:num(r['Amount spent (USD)']),
    conversions:num(r['Results']), roas:num(r['Purchase ROAS (return on ad spend)']),
    cpm:num(r['CPM (cost per 1,000 impressions) (USD)']),
    purchases:num(r['Purchases']), budget:num(r['Ad set budget']),
  };
  return null;
}

function agg(data) {
  const impressions = data.reduce((s,r)=>s+r.impressions,0);
  const clicks      = data.reduce((s,r)=>s+r.clicks,0);
  const spend       = data.reduce((s,r)=>s+r.spend,0);
  const conversions = data.reduce((s,r)=>s+r.conversions,0);
  const purchases   = data.reduce((s,r)=>s+r.purchases,0);
  return {
    impressions, clicks, spend:+spend.toFixed(2), conversions, purchases,
    ctr:  impressions>0&&clicks>0 ? +((clicks/impressions)*100).toFixed(2) : 0,
    cpc:  clicks>0 ? +(spend/clicks).toFixed(2) : 0,
    cpa:  conversions>0 ? +(spend/conversions).toFixed(2) : 0,
    cpm:  impressions>0 ? +((spend/impressions)*1000).toFixed(2) : 0,
  };
}

const rows      = items.map(i=>i.json).map(normalise).filter(Boolean);
const google    = rows.filter(r=>r.platform==='Google');
const microsoft = rows.filter(r=>r.platform==='Microsoft');
const meta      = rows.filter(r=>r.platform==='Meta' && r.spend>0);
const all       = [...google, ...microsoft.filter(r=>r.spend>0), ...meta];

const tG    = agg(google);
const tM    = agg(microsoft.filter(r=>r.spend>0));
const tMeta = agg(meta);
const tAll  = agg(all);
const totalSpend = tAll.spend || 1;

const bestMS      = [...microsoft].filter(r=>r.conversions>0).sort((a,b)=>b.conversions-a.conversions)[0];
const worstMeta   = [...meta].filter(r=>r.conversions===0&&r.spend>50).sort((a,b)=>b.spend-a.spend)[0];
const bestMeta    = [...meta].filter(r=>r.roas>0).sort((a,b)=>b.roas-a.roas)[0];
const budgetPaused = microsoft.filter(r=>String(r.status).toLowerCase().includes('budget'));

function campSummary(data) {
  return data.filter(r=>r.spend>0).map(r=>
    `  - ${r.campaign} | Spend:$${r.spend.toFixed(2)} | Impr:${r.impressions} | Conv:${r.conversions} | CPA:${r.conversions>0?'$'+(r.spend/r.conversions).toFixed(2):'N/A'} | ROAS:${r.roas>0?r.roas.toFixed(2)+'x':'N/A'}`
  ).join('\n');
}

const groqPrompt = `You are a senior digital marketing analyst. Analyze this February 2026 ad performance data for a health supplements brand (Biogetica) and provide expert insights.

ACCOUNT SUMMARY
Total Spend: $${tAll.spend} | Impressions: ${tAll.impressions.toLocaleString()} | Clicks: ${tAll.clicks} | Conversions: ${tAll.conversions} | Blended CPA: ${tAll.cpa>0?'$'+tAll.cpa:'N/A'}

PLATFORM BREAKDOWN
Meta: Spend $${tMeta.spend} (${((tMeta.spend/totalSpend)*100).toFixed(1)}%) | Impr: ${tMeta.impressions} | Conv: ${tMeta.conversions} | CPA: ${tMeta.cpa>0?'$'+tMeta.cpa:'N/A'} | CPM: $${tMeta.cpm}
Microsoft: Spend $${tM.spend} (${((tM.spend/totalSpend)*100).toFixed(1)}%) | Impr: ${tM.impressions} | Clicks: ${tM.clicks} | Conv: ${tM.conversions} | CPA: ${tM.cpa>0?'$'+tM.cpa:'N/A'}
Google: Spend $${tG.spend} (${((tG.spend/totalSpend)*100).toFixed(1)}%) | Impr: ${tG.impressions} | Clicks: ${tG.clicks} | Conv: ${tG.conversions}

META CAMPAIGNS
${campSummary(meta)}

MICROSOFT CAMPAIGNS
${campSummary(microsoft)}

GOOGLE CAMPAIGNS
${campSummary(google)}

KEY FLAGS
- Google: 0 conversions across all campaigns ($${tG.spend} spent)
- Budget-paused Microsoft: ${budgetPaused.map(r=>r.campaign).join(', ')||'None'}
- Best Meta ROAS: ${bestMeta?bestMeta.campaign+' ('+bestMeta.roas.toFixed(2)+'x)':'N/A'}
- Worst Meta waste: ${worstMeta?worstMeta.campaign+' ($'+worstMeta.spend.toFixed(2)+', 0 conv)':'None'}
- Best Microsoft: ${bestMS?bestMS.campaign+' ('+bestMS.conversions+' conv, $'+(bestMS.spend/bestMS.conversions).toFixed(2)+' CPA)':'N/A'}

Provide analysis in these exact sections. Use ONLY the data above — do not say you lack data:

### EXECUTIVE SUMMARY
2-3 sentences on overall account health and the single most important finding.

### WHAT'S WORKING
3 bullet points on top performers with exact numbers from the data above.

### WHAT NEEDS FIXING
3 bullet points on underperformers with exact numbers.

### AI RECOMMENDATIONS
5 prioritized actionable recommendations referencing actual campaign names and dollar amounts.

### MARCH 2026 FOCUS
3 bullet points on what to prioritize next month.`;

return [{
  json: {
    kpi: { tG, tM, tMeta, tAll, totalSpend, bestMS, worstMeta, bestMeta,
           budgetPaused: budgetPaused.map(r=>r.campaign), google, microsoft, meta },
    groqPrompt
  }
}];

// ============================================================
// Code Node 2: "Build - HTML Report"
// Reads kpi from Code1 + AI insights from Groq (merged item)
// ============================================================

const num = v => parseFloat(String(v).replace(/[,%$\s]/g,'')) || 0;
const fmt = v => Number(v).toLocaleString();
const usd = v => '$' + (+v).toFixed(2);

// ── Pull data — Merge By Position puts Code1+Groq into items[0] ──
const j            = items[0].json;
const kpi          = j.kpi          || {};
const tG           = kpi.tG         || {};
const tM           = kpi.tM         || {};
const tMeta        = kpi.tMeta      || {};
const tAll         = kpi.tAll       || {};
const totalSpend   = kpi.totalSpend || 1;
const google       = kpi.google     || [];
const microsoft    = kpi.microsoft  || [];
const meta         = kpi.meta       || [];
const budgetPaused = kpi.budgetPaused || [];
const aiRaw        = j.choices?.[0]?.message?.content || '';

// ── Spend shares ──
const metaPct = ((( tMeta.spend||0)/totalSpend)*100).toFixed(1);
const msPct   = (((tM.spend||0)/totalSpend)*100).toFixed(1);
const gPct    = (((tG.spend||0)/totalSpend)*100).toFixed(1);

// ── SVG: Spend donut ──
function donut() {
  const data = [
    {l:'Meta',      v:tMeta.spend||0, c:'#334155'},
    {l:'Microsoft', v:tM.spend||0,    c:'#64748B'},
    {l:'Google',    v:tG.spend||0,    c:'#94A3B8'},
  ];
  const total = data.reduce((s,d)=>s+d.v,0)||1;
  const cx=75,cy=75,r=58,inn=32;
  let paths='',angle=-Math.PI/2;
  data.forEach(d=>{
    const a=(d.v/total)*2*Math.PI,end=angle+a;
    const x1=cx+r*Math.cos(angle),y1=cy+r*Math.sin(angle);
    const x2=cx+r*Math.cos(end),  y2=cy+r*Math.sin(end);
    const i1=cx+inn*Math.cos(angle),j1=cy+inn*Math.sin(angle);
    const i2=cx+inn*Math.cos(end),  j2=cy+inn*Math.sin(end);
    const lg=a>Math.PI?1:0;
    paths+=`<path d="M${i1},${j1}L${x1},${y1}A${r},${r} 0 ${lg},1 ${x2},${y2}L${i2},${j2}A${inn},${inn} 0 ${lg},0 ${i1},${j1}Z" fill="${d.c}"/>`;
    angle=end;
  });
  const legend=data.map((d,i)=>`
    <rect x="162" y="${14+i*26}" width="10" height="10" fill="${d.c}" rx="2"/>
    <text x="178" y="${24+i*26}" font-size="11" fill="#374151" font-family="Arial">${d.l}</text>
    <text x="178" y="${36+i*26}" font-size="10" fill="#6B7280" font-family="Arial">$${d.v.toFixed(0)} · ${((d.v/total)*100).toFixed(1)}%</text>`).join('');
  return `<svg width="310" height="152" xmlns="http://www.w3.org/2000/svg">
    ${paths}
    <text x="${cx}" y="${cy+5}" text-anchor="middle" font-size="13" font-weight="bold" fill="#0F172A" font-family="Arial">$${total.toFixed(0)}</text>
    ${legend}</svg>`;
}

// ── SVG: Conversions bar ──
function convBars() {
  const data=[{l:'Meta',v:tMeta.conversions||0},{l:'Microsoft',v:tM.conversions||0},{l:'Google',v:tG.conversions||0}];
  const mx=Math.max(...data.map(d=>d.v),1);
  return `<svg width="270" height="100" xmlns="http://www.w3.org/2000/svg">
    ${data.map((d,i)=>{
      const w=Math.round((d.v/mx)*160);
      return `<text x="0" y="${20+i*32}" font-size="11" fill="#374151" font-family="Arial">${d.l}</text>
        <rect x="75" y="${6+i*32}" width="${Math.max(w,3)}" height="16" fill="#334155" rx="2"/>
        <text x="${75+Math.max(w,3)+6}" y="${20+i*32}" font-size="11" fill="#374151" font-family="Arial">${d.v}</text>`;
    }).join('')}</svg>`;
}

// ── Table styles ──
const TH  = 'padding:9px 12px;font-size:11px;font-weight:600;color:#fff;text-align:left;background:#1E293B;';
const THR = 'padding:9px 12px;font-size:11px;font-weight:600;color:#fff;text-align:right;background:#1E293B;';
const TD  = 'padding:8px 12px;font-size:11px;color:#374151;border-bottom:1px solid #F1F5F9;';
const TDR = 'padding:8px 12px;font-size:11px;color:#374151;border-bottom:1px solid #F1F5F9;text-align:right;';
const TDF = 'padding:8px 12px;font-size:11px;font-weight:700;color:#0F172A;border-top:2px solid #E2E8F0;';
const TDFR= 'padding:8px 12px;font-size:11px;font-weight:700;color:#0F172A;border-top:2px solid #E2E8F0;text-align:right;';

function dot(s){
  const ok=s==='active'||s==='Enabled';
  return `<span style="display:inline-block;width:6px;height:6px;border-radius:50%;background:${ok?'#22C55E':'#CBD5E1'};margin-right:6px;vertical-align:middle;"></span>`;
}
function badge(txt,color){return `<span style="font-size:9px;background:${color};color:#fff;padding:1px 6px;border-radius:3px;margin-left:4px;vertical-align:middle;">${txt}</span>`;}
function trim(s,n=42){return s.length>n?s.substring(0,n)+'…':s;}

function metaRows(){
  return meta.map((r,i)=>{
    const bg=i%2===0?'#fff':'#F8FAFC';
    const cpa=r.conversions>0?usd((r.spend/r.conversions).toFixed(2)):'—';
    const roas=r.roas>0?r.roas.toFixed(2)+'x':'—';
    return `<tr style="background:${bg}">
      <td style="${TD}">${dot(r.status)}${trim(r.campaign)}</td>
      <td style="${TDR}">${usd(r.spend)}</td>
      <td style="${TDR}">${fmt(r.impressions)}</td>
      <td style="${TDR}">${r.cpm>0?usd(r.cpm.toFixed(2)):'—'}</td>
      <td style="${TDR}">${r.conversions||'—'}</td>
      <td style="${TDR}">${cpa}</td>
      <td style="${TDR}">${roas}</td></tr>`;
  }).join('')+`<tr>
    <td style="${TDF}">Total</td>
    <td style="${TDFR}">${usd(tMeta.spend)}</td>
    <td style="${TDFR}">${fmt(tMeta.impressions)}</td>
    <td style="${TDFR}">—</td>
    <td style="${TDFR}">${tMeta.conversions}</td>
    <td style="${TDFR}">${tMeta.cpa>0?usd(tMeta.cpa.toFixed(2)):'—'}</td>
    <td style="${TDFR}">—</td></tr>`;
}

function msRows(){
  return microsoft.map((r,i)=>{
    const bg=i%2===0?'#fff':'#F8FAFC';
    const paused=String(r.status).toLowerCase().includes('budget');
    const cpa=r.conversions>0?usd((r.spend/r.conversions).toFixed(2)):'—';
    return `<tr style="background:${bg}">
      <td style="${TD}">${dot(r.status)}${trim(r.campaign)}${paused?badge('BUDGET PAUSED','#94A3B8'):''}</td>
      <td style="${TDR}">${usd(r.spend)}</td>
      <td style="${TDR}">${fmt(r.impressions)}</td>
      <td style="${TDR}">${r.clicks||'—'}</td>
      <td style="${TDR}">${r.ctr||'—'}</td>
      <td style="${TDR}">${r.conversions||'—'}</td>
      <td style="${TDR}">${cpa}</td></tr>`;
  }).join('')+`<tr>
    <td style="${TDF}">Total</td>
    <td style="${TDFR}">${usd(tM.spend)}</td>
    <td style="${TDFR}">${fmt(tM.impressions)}</td>
    <td style="${TDFR}">${fmt(tM.clicks)}</td>
    <td style="${TDFR}">—</td>
    <td style="${TDFR}">${tM.conversions}</td>
    <td style="${TDFR}">${tM.cpa>0?usd(tM.cpa.toFixed(2)):'—'}</td></tr>`;
}

function gRows(){
  return google.map((r,i)=>{
    const bg=i%2===0?'#fff':'#F8FAFC';
    return `<tr style="background:${bg}">
      <td style="${TD}">${dot(r.status)}${trim(r.campaign)}</td>
      <td style="${TDR}">${usd(r.spend)}</td>
      <td style="${TDR}">${fmt(r.impressions)}</td>
      <td style="${TDR}">${r.clicks||'—'}</td>
      <td style="${TDR}">${r.conversions||'—'}</td>
      <td style="${TDR}">${r.type||'—'}</td></tr>`;
  }).join('');
}

// ── Format AI insights ──
function formatAI(text) {
  if(!text||text.length<20) return '<p style="color:#94A3B8;font-size:12px;">AI insights not available for this run.</p>';
  return text
    .replace(/### (.*)/g,'<h3 style="font-size:13px;font-weight:700;color:#0F172A;margin:20px 0 8px;padding-bottom:6px;border-bottom:1px solid #E2E8F0;">$1</h3>')
    .replace(/\*\*(.*?)\*\*/g,'<strong>$1</strong>')
    .replace(/^- (.*)/gm,'<div style="display:flex;gap:8px;margin-bottom:6px;"><span style="color:#64748B;margin-top:1px;">•</span><span style="font-size:12px;color:#374151;line-height:1.6;">$1</span></div>')
    .replace(/\n\n/g,'<br/>')
    .replace(/\n/g,'');
}

// ── Section header ──
function secH(title, sub=''){
  return `<h2 style="font-size:13px;font-weight:700;color:#0F172A;margin:0 0 ${sub?'4':'14'}px;padding-bottom:8px;border-bottom:2px solid #E2E8F0;letter-spacing:0.3px;">${title}</h2>${sub?`<p style="font-size:11px;color:#94A3B8;margin:0 0 12px;">${sub}</p>`:''}`;
}

const now = new Date().toLocaleDateString('en-IN',{month:'long',year:'numeric'});

const html = `<!DOCTYPE html>
<html lang="en"><head><meta charset="UTF-8"></head>
<body style="margin:0;padding:0;background:#F8FAFC;font-family:Arial,sans-serif;">
<table width="100%" cellpadding="0" cellspacing="0" style="background:#F8FAFC;padding:20px 0;">
<tr><td align="center">
<table width="660" cellpadding="0" cellspacing="0" style="background:#fff;border-radius:8px;overflow:hidden;border:1px solid #E2E8F0;">

<!-- HEADER -->
<tr><td style="background:#0F172A;padding:24px 32px;">
  <table width="100%"><tr valign="middle">
    <td>
      <div style="font-size:10px;color:#64748B;letter-spacing:2px;text-transform:uppercase;margin-bottom:4px;">Monthly Performance Report · February 2026</div>
      <h1 style="color:#F8FAFC;margin:0;font-size:20px;font-weight:700;">Campaign Intelligence Report</h1>
      <p style="color:#64748B;margin:5px 0 0;font-size:12px;">Meta · Microsoft · Google &nbsp;|&nbsp; Powered by Groq AI (Llama 3.3 70B)</p>
    </td>
    <td align="right">
      <div style="text-align:right;">
        <div style="font-size:22px;font-weight:700;color:#F8FAFC;">${usd(tAll.spend)}</div>
        <div style="font-size:10px;color:#64748B;">Total Spend</div>
      </div>
    </td>
  </tr></table>
</td></tr>

<!-- KPI STRIP -->
<tr><td style="background:#1E293B;padding:0;">
  <table width="100%" cellpadding="0" cellspacing="0"><tr>
    ${[
      [fmt(tAll.impressions),'Impressions'],
      [fmt(tAll.clicks),'Clicks'],
      [String(tAll.conversions),'Conversions'],
      [tAll.cpa>0?usd(tAll.cpa.toFixed(2)):'—','Avg. CPA'],
      [String(tAll.purchases),'Purchases'],
    ].map(([v,l],i)=>`<td style="padding:16px 0;text-align:center;${i<4?'border-right:1px solid #334155;':''}">
      <div style="font-size:17px;font-weight:700;color:#F8FAFC;">${v}</div>
      <div style="font-size:10px;color:#64748B;margin-top:3px;text-transform:uppercase;letter-spacing:0.5px;">${l}</div>
    </td>`).join('')}
  </tr></table>
</td></tr>

<!-- CHARTS -->
<tr><td style="padding:24px 32px 8px;">
  ${secH('Performance Breakdown')}
  <table width="100%" cellpadding="0" cellspacing="0"><tr valign="top">
    <td width="49%" style="background:#F8FAFC;border-radius:6px;padding:16px;border:1px solid #E2E8F0;text-align:center;">
      <div style="font-size:10px;font-weight:600;color:#64748B;text-transform:uppercase;letter-spacing:1px;margin-bottom:10px;">Spend Distribution</div>
      ${donut()}
    </td>
    <td width="2%"></td>
    <td width="49%" style="background:#F8FAFC;border-radius:6px;padding:16px;border:1px solid #E2E8F0;">
      <div style="font-size:10px;font-weight:600;color:#64748B;text-transform:uppercase;letter-spacing:1px;margin-bottom:10px;text-align:center;">Conversions by Platform</div>
      ${convBars()}
    </td>
  </tr></table>
</td></tr>

<!-- PLATFORM SUMMARY -->
<tr><td style="padding:16px 32px 8px;">
  ${secH('Platform Summary')}
  <table width="100%" cellpadding="0" cellspacing="0" style="border:1px solid #E2E8F0;border-radius:6px;overflow:hidden;">
    <tr><th style="${TH}">Platform</th><th style="${THR}">Spend</th><th style="${THR}">Share</th><th style="${THR}">Impressions</th><th style="${THR}">Clicks</th><th style="${THR}">CPM</th><th style="${THR}">Conv.</th><th style="${THR}">CPA</th></tr>
    <tr style="background:#fff"><td style="${TD}">Meta</td><td style="${TDR}">${usd(tMeta.spend)}</td><td style="${TDR}">${metaPct}%</td><td style="${TDR}">${fmt(tMeta.impressions)}</td><td style="${TDR}">—</td><td style="${TDR}">${tMeta.cpm>0?usd(tMeta.cpm.toFixed(2)):'—'}</td><td style="${TDR}">${tMeta.conversions}</td><td style="${TDR}">${tMeta.cpa>0?usd(tMeta.cpa.toFixed(2)):'—'}</td></tr>
    <tr style="background:#F8FAFC"><td style="${TD}">Microsoft</td><td style="${TDR}">${usd(tM.spend)}</td><td style="${TDR}">${msPct}%</td><td style="${TDR}">${fmt(tM.impressions)}</td><td style="${TDR}">${fmt(tM.clicks)}</td><td style="${TDR}">${tM.cpm>0?usd(tM.cpm.toFixed(2)):'—'}</td><td style="${TDR}">${tM.conversions}</td><td style="${TDR}">${tM.cpa>0?usd(tM.cpa.toFixed(2)):'—'}</td></tr>
    <tr style="background:#fff"><td style="${TD}">Google</td><td style="${TDR}">${usd(tG.spend)}</td><td style="${TDR}">${gPct}%</td><td style="${TDR}">${fmt(tG.impressions)}</td><td style="${TDR}">${fmt(tG.clicks)}</td><td style="${TDR}">—</td><td style="${TDR}">${tG.conversions}</td><td style="${TDR}">—</td></tr>
    <tr><td style="${TDF}">Total</td><td style="${TDFR}">${usd(tAll.spend)}</td><td style="${TDFR}">100%</td><td style="${TDFR}">${fmt(tAll.impressions)}</td><td style="${TDFR}">${fmt(tAll.clicks)}</td><td style="${TDFR}">—</td><td style="${TDFR}">${tAll.conversions}</td><td style="${TDFR}">${tAll.cpa>0?usd(tAll.cpa.toFixed(2)):'—'}</td></tr>
  </table>
</td></tr>

<!-- META TABLE -->
<tr><td style="padding:16px 32px 8px;">
  ${secH('Meta Campaigns', `${meta.length} campaigns · February 2026`)}
  <table width="100%" cellpadding="0" cellspacing="0" style="border:1px solid #E2E8F0;border-radius:6px;overflow:hidden;">
    <tr><th style="${TH}">Campaign</th><th style="${THR}">Spend</th><th style="${THR}">Impr.</th><th style="${THR}">CPM</th><th style="${THR}">Conv.</th><th style="${THR}">CPA</th><th style="${THR}">ROAS</th></tr>
    ${metaRows()}
  </table>
</td></tr>

<!-- MICROSOFT TABLE -->
<tr><td style="padding:16px 32px 8px;">
